import{_ as a,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"虫之呼吸","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/虫之呼吸.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/虫之呼吸.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/虫之呼吸.md"};function d(l,r,_,b,i,c){return t(),p("div",null,[...r[0]||(r[0]=[e("h1",{id:"虫之呼吸",tabindex:"-1"},[n("虫之呼吸 "),e("a",{class:"header-anchor",href:"#虫之呼吸","aria-label":'Permalink to "虫之呼吸"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌039")])])],-1),s('<h1 id="虫之呼吸-1" tabindex="-1">虫之呼吸 <a class="header-anchor" href="#虫之呼吸-1" aria-label="Permalink to &quot;虫之呼吸&quot;">​</a></h1><p>技艺<br> 虫之呼吸<br> 前置：呼吸法初级训练<br> 下属技艺使用条件：具有涂毒刀鞘，使用涂毒刀鞘绑定的武器（涂毒刀鞘请详见物品与装备-奇物-系列物品-涂毒刀鞘）</p><p>基于基础流派水之呼吸的衍生——花之呼吸而创造出的虫之呼吸，相关招式为高速击刺技与毒素的结合，以此来弥补创造者因腕力太小而不足以斩下鬼头的缺憾。</p><p>因为招式的直接攻击威力比起其他呼吸法略显逊色，通常需要在刀上涂抹毒素才能发挥效果。</p><p>虫之呼吸的相关招式不以“几之型”命名，而是皆以“舞”来命名。</p><p>虫之呼吸不需要按顺序购买。</p><p>【呼吸】<br> 拥有该词条的单位在进行一次以生理属性作为关键属性的攻击前须投掷一个D10的自然骰，若出目不大于呼吸层数，则令这次攻击造成的伤害增加一半并消耗一层呼吸层数。<br> 一个单位的具有呼吸层数上限为10层。<br> 呼吸层数会在战斗结束时清空。</p><p>蝶之舞-戏弄<br> C+1000<br> 如同蝴蝶飞舞一般移动，用较轻的力度瞬间进行五连突刺。</p><p>以一整轮动作消耗2点呼吸法发动一次冲锋攻击，这次冲锋的移动行为结束后，即使对方离开了攻击范围，也可以按照脱离攻击范围一般进行冲锋攻击 ，并且被攻击的单位还会额外受到1点多次攻击减值，该次攻击结束后，使用者获得2层【呼吸】，该次攻击命中时会使目标获得1点不可豁免的毒素异常点，效果的来源和等级与涂毒刀鞘的来源和等级相同。</p><p>蜂牙之舞-真曳<br> C+1000<br> 使用沾有毒素的细剑向前猛烈突刺。</p><p>以一个标准动作消耗4点呼吸法发动一次近战攻击，本次攻击具有4点速度加值，命中目标后目标需以强韧豁免该次伤害出目，目标豁免失败则其在强韧豁免获得【劣化2】，持续一场景，效果的来源和等级与涂毒刀鞘的来源和等级相同。</p><p>蜻蛉之舞-复眼六角<br> B+2500<br> 瞬间进行六连突刺，连续将大量毒素打入体内。</p><p>以一个标准动作消耗6点呼吸法发动一次近战攻击，你可以在本次攻击结束后令对方身上的毒素异常点数立刻生效一次，这是一个激爆效果，在这次攻击结束后，使用者获得3层【呼吸】。</p><p>虫之呼吸-蜈蚣之舞：<br> C+1000<br> 通过猛烈踏地来达到令对手难以捕捉身形的超高速行动，步法变换莫测，如同向四面八方扭曲翻滚。</p><p>虫之呼吸-蜈蚣之舞以一个移动动作消耗2点呼吸法进行一次移动，对于与你交战的敌人而言，你的移动看起来就像瞬间消失了一般，你移动后进行的第一次攻击具有C级的措手不及且额外具有5高速，你的移动速度增加30米。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
